customCSS:
@import url('https://fonts.googleapis.com/css2?family=Cinzel:wght@600;700&family=Inter:wght@400;500;600&family=JetBrains+Mono:wght@400;500&display=swap');

/* ===== Override hardcoded base ===== */
body { font-family: 'Inter','Segoe UI',sans-serif !important; color: #e8e2d2 !important; }

.overlay-container.interactive { border: 1px solid rgba(95,216,200,0.35) !important; border-radius: 6px !important; }
.overlay-container.click-through { border: 1px solid rgba(95,216,200,0.18) !important; border-radius: 6px !important; }

/* ===== Header ===== */
.header { padding: 10px 14px !important; background: linear-gradient(180deg, rgba(35,28,52,0.92), rgba(20,17,31,0.88)) !important; border-bottom: 1px solid rgba(212,168,87,0.28) !important; position: relative !important; }
.header::after { content: ''; position: absolute; left: 14px; right: 14px; bottom: -1px; height: 1px; background: linear-gradient(90deg, transparent, rgba(212,168,87,0.5), transparent); pointer-events: none; }
.header h2 { font-family: 'Cinzel','Inter',serif !important; color: #f1d990 !important; font-weight: 700 !important; letter-spacing: 0.18em !important; text-transform: uppercase !important; font-size: 13px !important; text-shadow: 0 0 12px rgba(212,168,87,0.25), 0 1px 2px rgba(0,0,0,0.6) !important; }
.header h2 #shortcut-hint { letter-spacing: 0 !important; text-transform: none !important; font-family: 'Inter',sans-serif !important; color: rgba(184,176,154,0.6) !important; text-shadow: none !important; font-weight: 400 !important; }

/* ===== Header buttons ===== */
.header-btn { background: rgba(212,168,87,0.12) !important; color: #f1d990 !important; border: 1px solid rgba(212,168,87,0.3) !important; border-radius: 4px !important; font-weight: 500 !important; transition: all .2s ease !important; }
.header-btn:hover { background: rgba(212,168,87,0.25) !important; color: #fff2cf !important; border-color: rgba(212,168,87,0.6) !important; }
.header-btn.close { background: rgba(197,74,58,0.18) !important; color: #f0a896 !important; border-color: rgba(197,74,58,0.4) !important; }
.header-btn.close:hover { background: rgba(197,74,58,0.45) !important; color: #ffe1d6 !important; border-color: rgba(197,74,58,0.8) !important; }

/* ===== Template + add buttons ===== */
.template-btn { background: linear-gradient(180deg, rgba(20,40,46,0.9), rgba(10,18,22,0.95)) !important; color: #5fd8c8 !important; border: 1px solid rgba(95,216,200,0.4) !important; border-radius: 4px !important; font-family: 'Cinzel','Inter',sans-serif !important; letter-spacing: 0.06em !important; font-size: 11px !important; font-weight: 600 !important; padding: 5px 10px !important; transition: all .2s ease !important; }
.template-btn:hover { color: #f1d990 !important; border-color: rgba(212,168,87,0.6) !important; box-shadow: 0 0 14px rgba(212,168,87,0.18) !important; }
.template-btn.danger { color: #f0a896 !important; border-color: rgba(197,74,58,0.45) !important; background: linear-gradient(180deg, rgba(45,18,14,0.9), rgba(25,10,8,0.95)) !important; }
.template-btn.danger:hover { color: #ffd7c8 !important; border-color: rgba(227,128,74,0.8) !important; box-shadow: 0 0 14px rgba(227,128,74,0.25) !important; }
.add-btn { background: linear-gradient(180deg, rgba(45,38,18,0.55) 0%, rgba(28,22,10,0.7) 100%) !important; color: #f1d990 !important; border: 1px solid rgba(212,168,87,0.5) !important; border-radius: 4px !important; font-family: 'Cinzel','Inter',sans-serif !important; font-weight: 600 !important; letter-spacing: 0.14em !important; text-transform: uppercase !important; font-size: 11px !important; padding: 7px 14px !important; box-shadow: inset 0 1px 0 rgba(212,168,87,0.12) !important; transition: all .2s ease !important; }
.add-btn:hover { color: #fff2cf !important; border-color: rgba(212,168,87,0.85) !important; background: linear-gradient(180deg, rgba(60,48,22,0.65) 0%, rgba(38,28,12,0.8) 100%) !important; box-shadow: inset 0 1px 0 rgba(212,168,87,0.2), 0 0 14px rgba(212,168,87,0.25) !important; }
.add-btn:active { transform: translateY(1px) !important; }

/* Override inline-styled green community/click-through buttons */
button[onclick*='loadCommunityTemplates'], button[onclick*='toggleInteractiveMode'] { background: linear-gradient(180deg, rgba(20,40,46,0.9), rgba(10,18,22,0.95)) !important; color: #5fd8c8 !important; border: 1px solid rgba(95,216,200,0.45) !important; }
button[onclick*='loadCommunityTemplates']:hover, button[onclick*='toggleInteractiveMode']:hover { color: #f1d990 !important; border-color: rgba(212,168,87,0.6) !important; box-shadow: 0 0 14px rgba(212,168,87,0.18) !important; }

/* ===== Inputs ===== */
.task-input, .modal-input, .template-select, input[type='text'], textarea, select { background: rgba(7,6,13,0.7) !important; border: 1px solid rgba(212,168,87,0.18) !important; color: #e8e2d2 !important; border-radius: 4px !important; transition: border-color .2s, box-shadow .2s !important; }
.task-input:focus, .modal-input:focus, .template-select:focus, input[type='text']:focus, textarea:focus, select:focus { outline: 0 !important; border-color: rgba(95,216,200,0.6) !important; box-shadow: 0 0 0 2px rgba(95,216,200,0.12) !important; }
.task-input::placeholder, .modal-input::placeholder { color: rgba(184,176,154,0.45) !important; }

/* ===== Progress bar ===== */
.progress-bar { height: 6px !important; background: rgba(255,255,255,0.05) !important; border-radius: 3px !important; box-shadow: inset 0 1px 2px rgba(0,0,0,0.5) !important; overflow: hidden !important; }
.progress-fill { background: linear-gradient(90deg, #2a8e84 0%, #5fd8c8 80%) !important; box-shadow: 0 0 12px rgba(95,216,200,0.5) !important; border-radius: 3px !important; }
.progress-text { color: #b8b09a !important; font-family: 'JetBrains Mono','Inter',monospace !important; letter-spacing: 0.06em !important; }

/* ===== Tasks ===== */
.task-section-label { font-family: 'Cinzel','Inter',serif !important; color: #d4a857 !important; letter-spacing: 0.18em !important; text-transform: uppercase !important; font-size: 10px !important; padding: 8px 4px 4px !important; border-bottom: 1px dashed rgba(212,168,87,0.18) !important; margin-bottom: 4px !important; }
.task-item { border-bottom: 1px solid rgba(255,255,255,0.04) !important; transition: background .2s, border-color .2s !important; }
.task-item:hover { background: rgba(212,168,87,0.05) !important; }
.task-checkbox { width: 14px !important; height: 14px !important; accent-color: #5fd8c8 !important; cursor: pointer !important; }
.task-text { color: #e8e2d2 !important; }
.task-text.completed { color: #7a7363 !important; text-decoration-color: rgba(95,216,200,0.5) !important; }
.task-delete { background: rgba(197,74,58,0.18) !important; color: #f0a896 !important; border: 1px solid rgba(197,74,58,0.35) !important; border-radius: 3px !important; transition: all .2s !important; }
.task-delete:hover { background: rgba(227,128,74,0.4) !important; color: #ffe1d6 !important; border-color: rgba(227,128,74,0.7) !important; }

/* Hierarchy */
.task-item[data-level='1'] { border-left: 2px solid rgba(95,216,200,0.25) !important; }
.task-item[data-level='1']:hover { background: rgba(95,216,200,0.05) !important; border-left-color: rgba(95,216,200,0.6) !important; }
.child-count { background: rgba(95,216,200,0.12) !important; color: #5fd8c8 !important; border: 1px solid rgba(95,216,200,0.3) !important; }

/* ===== Background tasks ===== */
.background-label { color: #e3804a !important; border-top: 1px solid rgba(227,128,74,0.25) !important; }
.background-count { color: rgba(184,176,154,0.55) !important; font-family: 'JetBrains Mono','Inter',monospace !important; }
.background-task-list .task-item { border-left: 2px solid rgba(227,128,74,0.5) !important; margin-left: 4px !important; }
.background-task-list .task-item.high-priority { border-left-color: #e3804a !important; box-shadow: -2px 0 12px rgba(227,128,74,0.3) !important; }
@keyframes pulseBorder { 0%,100% { border-left-color: #e3804a; } 50% { border-left-color: #ffb066; } }
.task-item .trigger-indicator { color: #d4a857 !important; }
.right-click-hint { color: rgba(212,168,87,0.55) !important; }

/* ===== Modal ===== */
.modal { background: rgba(0,0,0,0.85) !important; backdrop-filter: blur(4px) !important; -webkit-backdrop-filter: blur(4px) !important; }
.modal-content { background: linear-gradient(180deg, rgba(20,17,31,0.98), rgba(11,9,18,0.98)) !important; border: 1px solid rgba(212,168,87,0.4) !important; border-radius: 8px !important; box-shadow: 0 24px 60px -10px rgba(0,0,0,0.85), 0 0 40px rgba(95,216,200,0.08) !important; position: relative !important; }
.modal-content::before { content: ''; position: absolute; top: 0; left: 0; right: 0; height: 1px; background: linear-gradient(90deg, transparent, rgba(212,168,87,0.5), transparent); pointer-events: none; }
.modal-title { font-family: 'Cinzel','Inter',serif !important; color: #f1d990 !important; letter-spacing: 0.14em !important; text-transform: uppercase !important; font-weight: 700 !important; }
.modal-content h4 { font-family: 'Cinzel','Inter',serif !important; color: #d4a857 !important; letter-spacing: 0.12em !important; text-transform: uppercase !important; }
.modal-btn.primary { background: linear-gradient(180deg, rgba(45,38,18,0.55) 0%, rgba(28,22,10,0.7) 100%) !important; color: #f1d990 !important; border: 1px solid rgba(212,168,87,0.5) !important; font-family: 'Cinzel','Inter',sans-serif !important; font-weight: 600 !important; letter-spacing: 0.12em !important; text-transform: uppercase !important; box-shadow: inset 0 1px 0 rgba(212,168,87,0.12) !important; transition: all .2s ease !important; }
.modal-btn.primary:hover { color: #fff2cf !important; border-color: rgba(212,168,87,0.85) !important; background: linear-gradient(180deg, rgba(60,48,22,0.65) 0%, rgba(38,28,12,0.8) 100%) !important; box-shadow: inset 0 1px 0 rgba(212,168,87,0.2), 0 0 14px rgba(212,168,87,0.25) !important; }
.modal-btn.secondary { background: linear-gradient(180deg, rgba(20,40,46,0.9), rgba(10,18,22,0.95)) !important; color: #5fd8c8 !important; border: 1px solid rgba(95,216,200,0.45) !important; font-family: 'Cinzel','Inter',sans-serif !important; font-weight: 600 !important; letter-spacing: 0.06em !important; }
.modal-btn.secondary:hover { color: #f1d990 !important; border-color: rgba(212,168,87,0.6) !important; }
.community-template { background: rgba(11,9,18,0.5) !important; border: 1px solid rgba(212,168,87,0.18) !important; border-radius: 6px !important; }
.community-template h4 { color: #d4a857 !important; font-family: 'Cinzel','Inter',serif !important; letter-spacing: 0.1em !important; text-transform: uppercase !important; }
.community-template .description { color: #b8b09a !important; }
.community-template .task-count { color: rgba(184,176,154,0.55) !important; }

/* ===== Context menu ===== */
.context-menu { background: linear-gradient(180deg, rgba(20,17,31,0.98), rgba(11,9,18,0.98)) !important; border: 1px solid rgba(212,168,87,0.4) !important; box-shadow: 0 12px 30px rgba(0,0,0,0.7), 0 0 0 1px rgba(0,0,0,0.4) !important; }
.context-menu div { color: #e8e2d2 !important; font-family: 'Inter',sans-serif !important; }
.context-menu div:hover { background: linear-gradient(90deg, rgba(212,168,87,0.18), rgba(212,168,87,0.06)) !important; color: #f1d990 !important; }

/* ===== Notification toast ===== */
.bg-task-notification { background: linear-gradient(180deg, rgba(35,28,52,0.96), rgba(20,17,31,0.96)) !important; border: 1px solid rgba(227,128,74,0.5) !important; color: #ffd7c8 !important; box-shadow: 0 12px 30px rgba(0,0,0,0.7), 0 0 24px rgba(227,128,74,0.25) !important; border-radius: 6px !important; font-weight: 500 !important; }

/* ===== Scrollbar ===== */
.tasks-section::-webkit-scrollbar, #settingsModal .modal-content::-webkit-scrollbar { width: 6px !important; }
.tasks-section::-webkit-scrollbar-track, #settingsModal .modal-content::-webkit-scrollbar-track { background: rgba(7,6,13,0.4) !important; }
.tasks-section::-webkit-scrollbar-thumb, #settingsModal .modal-content::-webkit-scrollbar-thumb { background: rgba(212,168,87,0.35) !important; border-radius: 3px !important; }
.tasks-section::-webkit-scrollbar-thumb:hover, #settingsModal .modal-content::-webkit-scrollbar-thumb:hover { background: rgba(212,168,87,0.6) !important; }

/* ===== Range slider ===== */
input[type='range'] { -webkit-appearance: none !important; appearance: none !important; background: transparent !important; height: 22px !important; }
input[type='range']::-webkit-slider-runnable-track { height: 4px !important; background: linear-gradient(90deg, #2a8e84, rgba(255,255,255,0.08)) !important; border-radius: 2px !important; }
input[type='range']::-webkit-slider-thumb { -webkit-appearance: none !important; appearance: none !important; width: 14px !important; height: 14px !important; border-radius: 50%; background: #f1d990 !important; box-shadow: 0 0 0 1px rgba(0,0,0,0.4), 0 0 10px rgba(212,168,87,0.5) !important; margin-top: -5px !important; cursor: pointer !important; }

/* ===== Drag placeholder ===== */
@keyframes placeholderPulse { 0%,100% { background: rgba(212,168,87,0.18); } 50% { background: rgba(95,216,200,0.25); } }

/* ===== Subtle ambient corner glints (interactive only) ===== */
.overlay-container.interactive::before, .overlay-container.interactive::after { content: ''; position: absolute; width: 14px; height: 14px; border: 1px solid rgba(212,168,87,0.5); pointer-events: none; z-index: 2; }
.overlay-container.interactive::before { top: 4px; left: 4px; border-right: 0; border-bottom: 0; }
.overlay-container.interactive::after { bottom: 4px; right: 4px; border-left: 0; border-top: 0; }
